    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.get('/?status=done', async (req, res) => {
  try {
    const tasks = await tasksService.getDoneTasks(req.params.projectId);
    res.json({ tasks });
