      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const createTask = (projectId, title) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'todo' };
  tasksStore.push(task);
  return Promise.resolve(task);
};

const getTasks = (projectId) => {
  const tasks = tasksStore.filter(task => task.projectId === projectId);
  return Promise.resolve(tasks);
};

const getDoneTasks = (projectId) => {
  const doneTasks = tasksStore.filter(task => task.projectId === projectId && task.status === 'done');
  return Promise.resolve(doneTasks);
};

module.exports = { createTask, getTasks, getDoneTasks };"
